// Look for development paradigm section
const lines = FILE_CONTENT.split('\n');
let inParadigm = false;
let paradigm = null;
for (const line of lines) {
  if (line.includes('Development Paradigm')) {
    inParadigm = true;
    console.log('Found Development Paradigm section');
  }
  if (inParadigm && (line.includes('functional') || line.includes('object-oriented') || line.includes('OOP'))) {
    paradigm = line;
    console.log('Paradigm line:', line.trim());
  }
  if (inParadigm && line.startsWith('## ') && !line.includes('Development Paradigm')) {
    break;
  }
}
if (!paradigm) {
  console.log('No Development Paradigm section found in AGENTS.md');
}

// Also check mutation testing strategy
let inMutation = false;
for (const line of lines) {
  if (line.includes('Mutation Testing Strategy')) {
    inMutation = true;
    console.log('Found Mutation Testing Strategy section');
  }
  if (inMutation && line.trim().length > 0 && !line.startsWith('#')) {
    console.log('Mutation line:', line.trim());
  }
  if (inMutation && line.startsWith('## ') && !line.includes('Mutation Testing Strategy')) {
    break;
  }
}
if (!inMutation) {
  console.log('No Mutation Testing Strategy section found');
}

const yaml = require('yaml');
const doc = yaml.parse(FILE_CONTENT);
const keys = Object.keys(doc);
console.log('Top-level keys:', keys.join(', '));
// Find the key that contains steps
for (const key of keys) {
  if (Array.isArray(doc[key])) {
    console.log(`\n${key} (array, ${doc[key].length} items):`);
    doc[key].forEach((item, i) => {
      if (item.step_id || item.id) {
        console.log(`  ${item.step_id || item.id}: ${item.title || item.name || item.description || 'no title'}`);
        if (item.files_to_modify) console.log(`    files: ${item.files_to_modify.join(', ')}`);
        if (item.acceptance_criteria) console.log(`    AC count: ${item.acceptance_criteria.length}`);
        if (item.dependencies) console.log(`    deps: ${item.dependencies.join(', ')}`);
      }
    });
  } else if (typeof doc[key] === 'object' && doc[key] !== null) {
    console.log(`\n${key} (object):`, JSON.stringify(doc[key]).substring(0, 200));
  } else {
    console.log(`${key}: ${doc[key]}`);
  }
}

